/* ─── FIFA CARD ───────────────────────────────────────────────────── */
function FCard({ user, n, size="full", stats, onClick }) {
  const t = getTier(n);
  const nt = TIERS[TIERS.indexOf(t)+1];
  const prog = nt ? Math.min(100, ((n-t.min)/(nt.min-t.min))*100) : 100;
  const sv = stats || DEF_STATS;
  const isMini = size === "mini";
  const W = isMini ? 120 : 200;
  const H = isMini ? 166 : 280;
  return (
    <div onClick={onClick} style={{
      width:W, height:H, borderRadius: isMini?10:16, background:t.bg, position:"relative",
      overflow:"hidden", cursor:onClick?"pointer":"default",
      boxShadow:`0 0 ${isMini?16:28}px ${t.glow}, 0 ${isMini?6:12}px ${isMini?12:24}px rgba(0,0,0,.4)`,
      border:`${isMini?1.5:2}px solid ${t.brd}`, userSelect:"none", flexShrink:0,
    }}>
      <div style={{padding: isMini?"6px 8px 0":"11px 13px 0", position:"relative", zIndex:2}}>
        <div style={{display:"flex", justifyContent:"space-between", alignItems:"flex-start"}}>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1}}>
            <span style={{fontSize:isMini?22:36,fontWeight:900,color:t.text,lineHeight:1,fontFamily:"Arial Black,Arial"}}>{t.rat}</span>
            <span style={{fontSize:isMini?5:7,fontWeight:700,color:t.sub,letterSpacing:1,textTransform:"uppercase"}}>{t.id.toUpperCase()}</span>
            <div style={{display:"flex",gap:1}}>{Array.from({length:t.st}).map((_,i)=><span key={i} style={{fontSize:isMini?5:7,color:"#FFD700"}}>★</span>)}</div>
          </div>
          <div style={{textAlign:"right"}}>
            <div style={{fontSize:isMini?4.5:6.5,color:t.sub}}>A7JZ BAGHDAD</div>
            <div style={{fontSize:isMini?5:7,color:t.sub,marginTop:1}}>🇮🇶 BHD</div>
          </div>
        </div>
        <div style={{display:"flex",justifyContent:"center",margin:isMini?"4px 0 2px":"8px 0 4px"}}>
          <div style={{
            width:isMini?46:76, height:isMini?46:76, borderRadius:"50%",
            background:user?.avatar?`url(${user.avatar}) center/cover no-repeat`:"rgba(255,255,255,.15)",
            border:`${isMini?2:3}px solid ${t.brd}`,
            display:"flex",alignItems:"center",justifyContent:"center",
            fontSize:isMini?22:34, overflow:"hidden",
            boxShadow:`0 0 ${isMini?8:14}px ${t.glow}`,
          }}>
            {!user?.avatar && t.ico}
          </div>
        </div>
        <div style={{textAlign:"center",marginBottom:isMini?2:4}}>
          <div style={{fontSize:isMini?7:11,fontWeight:800,color:t.text,letterSpacing:.5,textTransform:"uppercase",fontFamily:"Arial Black,Arial",lineHeight:1.2}}>
            {(user?.name||"PLAYER").split(" ").slice(0,2).join(" ")}
          </div>
        </div>
      </div>
      <div style={{height:isMini?.5:1,background:`linear-gradient(to right,transparent,${t.brd},transparent)`,margin:`0 ${isMini?7:13}px`,opacity:.6}} />
      <div style={{padding:isMini?"3px 6px":"6px 11px",display:"flex",justifyContent:"space-around",position:"relative",zIndex:2}}>
        {Object.entries(sv).map(([k,v])=>(
          <div key={k} style={{textAlign:"center"}}>
            <div style={{fontSize:isMini?7:12,fontWeight:800,color:t.text,fontFamily:"Arial Black,Arial"}}>{Math.min(99,Math.max(1,Math.round(v)))}</div>
            <div style={{fontSize:isMini?4.5:6.5,color:t.sub,fontWeight:600,marginTop:.5}}>{k}</div>
          </div>
        ))}
      </div>
      <div style={{padding:isMini?"1px 6px 4px":"2px 12px 8px",textAlign:"center",position:"relative",zIndex:2}}>
        <div style={{fontSize:isMini?5.5:8.5,color:t.sub,fontWeight:600}}>{n} حجز{nt?` · ${nt.min-n} للترقية`:" · MAX"}</div>
        {!isMini && nt && (
          <div style={{marginTop:3,height:3,background:"rgba(0,0,0,.3)",borderRadius:2,overflow:"hidden"}}>
            <div style={{height:"100%",width:`${prog}%`,background:t.text,borderRadius:2,opacity:.8}} />
          </div>
        )}
      </div>
    </div>
  );
}

/* ─── STAT SLIDER ─────────────────────────────────────────────────── */
function StatSlider({ label, value, onChange }) {
  const [local, setLocal] = useState(Math.round(value));
  const c = local>=85?"#22c55e":local>=70?STAR:ER;
  const handle = (e) => {
    const v = +e.target.value;
    setLocal(v);
    onChange(v);
  };
  return (
    <div style={{display:"flex",flexDirection:"column",gap:6}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:12,fontWeight:700,color:TK}}>{label}</span>
        <span style={{fontSize:15,fontWeight:900,color:c,minWidth:30,textAlign:"right"}}>{local}</span>
      </div>
      <div style={{position:"relative",height:7,background:S3,borderRadius:4,overflow:"hidden"}}>
        <div style={{position:"absolute",left:0,top:0,height:"100%",width:`${local}%`,background:c,borderRadius:4}} />
      </div>
      <input
        type="range" min={1} max={99}
        value={local}
        onChange={handle}
        style={{width:"100%",margin:"2px 0",cursor:"pointer",accentColor:c}}
      />
    </div>
  );
}

/* ─── CANVAS MAP ──────────────────────────────────────────────────── */
function TileMap({ W, H, onBook }) {
  const cRef = useRef(null);
  const st = useRef({ z:12, lat:33.315, lng:44.366, drag:false, lx:0, ly:0, tiles:{}, pend:new Set(), uLat:null, uLng:null, sel:null });
  const [selP, setSelP] = useState(null);
  const TS = 256;

  const orig = useCallback(()=>{
    const s=st.current, n=Math.pow(2,s.z);
    const cx=(s.lng+180)/360*n;
    const cy=(1-Math.log(Math.tan(s.lat*Math.PI/180)+1/Math.cos(s.lat*Math.PI/180))/Math.PI)/2*n;
    return {ox:cx-W/2/TS, oy:cy-H/2/TS};
  },[W,H]);

  const l2s = useCallback((la,ln)=>{
    const s=st.current, n=Math.pow(2,s.z), {ox,oy}=orig();
    const px=(ln+180)/360*n*TS;
    const py=(1-Math.log(Math.tan(la*Math.PI/180)+1/Math.cos(la*Math.PI/180))/Math.PI)/2*n*TS;
    return {x:px-ox*TS, y:py-oy*TS};
  },[orig]);

  const draw = useCallback(()=>{
    const cv=cRef.current; if(!cv) return;
    const ctx=cv.getContext("2d"), s=st.current, n=Math.pow(2,s.z), {ox,oy}=orig();
    ctx.clearRect(0,0,W,H); ctx.fillStyle="#e8eff2"; ctx.fillRect(0,0,W,H);
    const tx0=Math.floor(ox), ty0=Math.floor(oy);
    for(let tx=tx0;tx<tx0+Math.ceil(W/TS)+2;tx++){
      for(let ty=ty0;ty<ty0+Math.ceil(H/TS)+2;ty++){
        const wx=((tx%n)+n)%n, key=`${s.z}/${wx}/${ty}`;
        const sx=(tx-ox)*TS, sy=(ty-oy)*TS;
        if(s.tiles[key]?.complete&&s.tiles[key].naturalWidth>0){
          ctx.drawImage(s.tiles[key],Math.round(sx),Math.round(sy),TS,TS);
        } else {
          ctx.fillStyle="#dce8ec"; ctx.fillRect(Math.round(sx),Math.round(sy),TS,TS);
          if(!s.tiles[key]&&!s.pend.has(key)){
            s.pend.add(key);
            const img=new Image(); img.crossOrigin="anonymous";
            img.src=`https://${"abc"[Math.abs(wx+ty)%3]}.tile.openstreetmap.org/${s.z}/${wx}/${ty}.png`;
            img.onload=()=>{ s.tiles[key]=img; s.pend.delete(key); draw(); };
            img.onerror=()=>{ s.tiles[key]=img; s.pend.delete(key); };
            s.tiles[key]=img;
          }
        }
      }
    }
    PITCHES.forEach((p,i)=>{
      const {x,y}=l2s(p.lat,p.lng);
      if(x<-20||x>W+20||y<-20||y>H+20) return;
      const sel=s.sel===p.id, r=sel?17:13;
      ctx.save(); ctx.shadowColor=sel?"rgba(44,96,110,.5)":"rgba(0,0,0,.25)"; ctx.shadowBlur=sel?10:5; ctx.shadowOffsetY=2;
      ctx.beginPath(); ctx.arc(x,y,r,0,Math.PI*2); ctx.fillStyle=sel?PD:P; ctx.fill();
      ctx.shadowColor="transparent"; ctx.beginPath(); ctx.arc(x,y,r,0,Math.PI*2);
      ctx.strokeStyle=sel?"#fff":"rgba(255,255,255,.7)"; ctx.lineWidth=sel?2.5:1.8; ctx.stroke(); ctx.restore();
      ctx.fillStyle="#fff"; ctx.font=`bold ${sel?11:9}px Arial`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText(String(i+1),x,y+.5);
    });
    if(s.uLat!==null){
      const {x,y}=l2s(s.uLat,s.uLng);
      ctx.beginPath(); ctx.arc(x,y,20,0,Math.PI*2); ctx.fillStyle="rgba(68,96,110,.12)"; ctx.fill();
      ctx.save(); ctx.shadowColor="rgba(68,96,110,.5)"; ctx.shadowBlur=8;
      ctx.beginPath(); ctx.arc(x,y,7,0,Math.PI*2); ctx.fillStyle=P; ctx.fill(); ctx.restore();
      ctx.beginPath(); ctx.arc(x,y,7,0,Math.PI*2); ctx.strokeStyle="#fff"; ctx.lineWidth=2.5; ctx.stroke();
    }
  },[W,H,orig,l2s]);

  const clamp = useCallback(()=>{
    const s=st.current; s.lat=Math.max(33.18,Math.min(33.47,s.lat)); s.lng=Math.max(44.24,Math.min(44.55,s.lng));
  },[]);

  const zoomAt = useCallback((sx,sy,f)=>{
    const s=st.current; const nz=Math.max(10,Math.min(18,s.z+f)); if(nz===s.z) return;
    const n0=Math.pow(2,s.z), {ox,oy}=orig();
    const lng=(ox+sx/TS)/n0*360-180;
    const lr=Math.PI-2*Math.PI*(oy+sy/TS)/n0;
    const lat=180/Math.PI*Math.atan(.5*(Math.exp(lr)-Math.exp(-lr)));
    s.z=nz;
    const n1=Math.pow(2,nz);
    const px=(lng+180)/360*n1*TS, py=(1-Math.log(Math.tan(lat*Math.PI/180)+1/Math.cos(lat*Math.PI/180))/Math.PI)/2*n1*TS;
    s.lng=((px/TS-sx/TS)+W/2/TS)/n1*360-180;
    const lr2=Math.PI-2*Math.PI*((py/TS-sy/TS)+H/2/TS)/n1;
    s.lat=180/Math.PI*Math.atan(.5*(Math.exp(lr2)-Math.exp(-lr2)));
    clamp(); draw();
  },[orig,W,H,clamp,draw]);

  const hitP = useCallback((sx,sy)=>{
    let h=null; PITCHES.forEach((p)=>{ const {x,y}=l2s(p.lat,p.lng); if(Math.sqrt((x-sx)**2+(y-sy)**2)<22) h=p; }); return h;
  },[l2s]);

  const flyTo = useCallback((la,ln,z=15)=>{
    const s=st.current, sl=s.lat, sn=s.lng, sz=s.z; let i=0;
    const ease=(t)=>t<.5?2*t*t:-1+(4-2*t)*t;
    const go=()=>{ i++; const t=ease(i/20); s.lat=sl+(la-sl)*t; s.lng=sn+(ln-sn)*t; s.z=Math.round(sz+(z-sz)*t); draw(); if(i<20) requestAnimationFrame(go); };
    requestAnimationFrame(go);
  },[draw]);

  useEffect(()=>{
    const cv=cRef.current; if(!cv) return;
    const gxy=(e)=>{ const r=cv.getBoundingClientRect(); return {x:(e.clientX-r.left)*(cv.width/r.width), y:(e.clientY-r.top)*(cv.height/r.height)}; };
    const md=(e)=>{ if(e.button!==0) return; const {x,y}=gxy(e); const p=hitP(x,y); if(p){st.current.sel=p.id;setSelP(p);draw();return;} st.current.sel=null;setSelP(null);st.current.drag=true;st.current.lx=e.clientX;st.current.ly=e.clientY; };
    const mm=(e)=>{ if(!st.current.drag) return; const dx=e.clientX-st.current.lx, dy=e.clientY-st.current.ly; st.current.lx=e.clientX;st.current.ly=e.clientY; const n=Math.pow(2,st.current.z); st.current.lng-=dx/TS/n*360; const my=Math.log(Math.tan(st.current.lat*Math.PI/180)+1/Math.cos(st.current.lat*Math.PI/180)); st.current.lat=Math.atan(Math.sinh(my+dy/TS/n*(2*Math.PI)))*180/Math.PI; clamp();draw(); };
    const mu=()=>{ st.current.drag=false; };
    const wh=(e)=>{ e.preventDefault(); const {x,y}=gxy(e); zoomAt(x,y,e.deltaY<0?1:-1); };
    const ts=(e)=>{ if(e.touches.length===1){ const t=e.touches[0],r=cv.getBoundingClientRect(); const x=(t.clientX-r.left)*(cv.width/r.width),y=(t.clientY-r.top)*(cv.height/r.height); const p=hitP(x,y); if(p){st.current.sel=p.id;setSelP(p);draw();}else{st.current.sel=null;setSelP(null);} st.current.drag=true;st.current.lx=t.clientX;st.current.ly=t.clientY; } e.preventDefault(); };
    const tm=(e)=>{ if(st.current.drag&&e.touches.length===1){ const t=e.touches[0]; const dx=t.clientX-st.current.lx,dy=t.clientY-st.current.ly; st.current.lx=t.clientX;st.current.ly=t.clientY; const n=Math.pow(2,st.current.z); st.current.lng-=dx/TS/n*360; const my=Math.log(Math.tan(st.current.lat*Math.PI/180)+1/Math.cos(st.current.lat*Math.PI/180)); st.current.lat=Math.atan(Math.sinh(my+dy/TS/n*(2*Math.PI)))*180/Math.PI; clamp();draw(); } e.preventDefault(); };
    const te=()=>{ st.current.drag=false; };
    cv.addEventListener("mousedown",md); window.addEventListener("mousemove",mm); window.addEventListener("mouseup",mu);
    cv.addEventListener("wheel",wh,{passive:false}); cv.addEventListener("touchstart",ts,{passive:false});
    cv.addEventListener("touchmove",tm,{passive:false}); cv.addEventListener("touchend",te);
    draw();
    return ()=>{ cv.removeEventListener("mousedown",md);window.removeEventListener("mousemove",mm);window.removeEventListener("mouseup",mu); cv.removeEventListener("wheel",wh);cv.removeEventListener("touchstart",ts);cv.removeEventListener("touchmove",tm);cv.removeEventListener("touchend",te); };
  },[draw,hitP,zoomAt,clamp]);

  const pop = selP ? (()=>{ const {x,y}=l2s(selP.lat,selP.lng); let px=x-95,py=y-150; if(px<6)px=6; if(px+190>W-6)px=W-196; if(py<6)py=y+18; return {px,py}; })() : null;

  return (
    <div style={{position:"relative",width:W,height:H,overflow:"hidden",borderRadius:16}}>
      <canvas ref={cRef} width={W} height={H} style={{display:"block",width:"100%",height:"100%",cursor:"grab"}} />
      <div style={{position:"absolute",left:10,top:10,display:"flex",flexDirection:"column",zIndex:10,gap:1}}>
        {[["＋",()=>zoomAt(W/2,H/2,1),"8px 8px 0 0"],["－",()=>zoomAt(W/2,H/2,-1),"0 0 8px 8px"]].map(([l,fn,br])=>(
          <button key={l} onClick={fn} style={{width:32,height:32,borderRadius:br,background:WH,border:"none",fontSize:17,fontWeight:600,cursor:"pointer",color:TK,boxShadow:"0 2px 8px rgba(0,0,0,.14)",display:"flex",alignItems:"center",justifyContent:"center"}}>{l}</button>
        ))}
      </div>
      <div style={{position:"absolute",right:10,bottom:14,display:"flex",flexDirection:"column",gap:7,zIndex:10}}>
        <button onClick={()=>{ navigator.geolocation?.getCurrentPosition((pos)=>{st.current.uLat=pos.coords.latitude;st.current.uLng=pos.coords.longitude;flyTo(pos.coords.latitude,pos.coords.longitude,15);},()=>flyTo(33.315,44.366,13),{timeout:6000}); }} style={{width:38,height:38,borderRadius:19,background:WH,border:"none",cursor:"pointer",boxShadow:"0 3px 10px rgba(0,0,0,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:17}}>📍</button>
        <button onClick={()=>flyTo(33.315,44.366,12)} style={{width:38,height:38,borderRadius:19,background:WH,border:"none",cursor:"pointer",boxShadow:"0 3px 10px rgba(0,0,0,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>⌂</button>
      </div>
      {selP&&pop&&(
        <div style={{position:"absolute",left:pop.px,top:pop.py,width:190,background:WH,borderRadius:14,boxShadow:"0 8px 28px rgba(0,0,0,.18)",border:`1px solid ${S3}`,padding:11,zIndex:20}}>
          <button onClick={()=>{st.current.sel=null;setSelP(null);draw();}} style={{position:"absolute",top:6,right:6,width:19,height:19,borderRadius:10,background:S2,border:"none",fontSize:10,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:T2}}>✕</button>
          <div style={{width:"100%",height:56,borderRadius:8,background:`linear-gradient(135deg,${selP.gr})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,marginBottom:7}}>{selP.em}</div>
          <div style={{fontSize:12,fontWeight:700,color:TK}}>{selP.ar}</div>
          <div style={{fontSize:10,color:T2,marginTop:2}}>📍 {selP.addr}</div>
          <div style={{fontSize:11,color:P,fontWeight:600,marginTop:3}}>{iqd(selP.pr)} / ساعة</div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:8}}>
            <span style={{fontSize:11,fontWeight:600,color:TK}}>⭐ {selP.rt.toFixed(1)}</span>
            <button onClick={()=>onBook(selP.id)} style={{background:P,color:"#fff",border:"none",borderRadius:8,padding:"5px 12px",fontSize:11,fontWeight:700,cursor:"pointer"}}>احجز ←</button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── STARTUP SCREEN ─────────────────────────────────────────────── */
function StartupScreen({ onDone }) {
  const [phase, setPhase] = useState(0);

  useEffect(()=>{
    const t1 = setTimeout(()=>setPhase(1), 100);
    const t2 = setTimeout(()=>setPhase(2), 700);
    const t3 = setTimeout(()=>setPhase(3), 1300);
    return ()=>{ clearTimeout(t1);clearTimeout(t2);clearTimeout(t3); };
  },[]);

  return (
    <div style={{position:"fixed",inset:0,background:`linear-gradient(160deg,${PD} 0%,${P} 50%,${PL} 100%)`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:9999,overflow:"hidden"}}>
      {/* animated background circles */}
      {[{w:520,h:520,op:.06,top:"-180px",left:"-160px",dur:"18s"},{w:380,h:380,op:.08,bottom:"-100px",right:"-80px",dur:"22s"},{w:250,h:250,op:.05,top:"40%",left:"60%",dur:"14s"}].map((c,i)=>(
        <div key={i} style={{position:"absolute",width:c.w,height:c.h,borderRadius:"50%",background:WH,opacity:c.op,top:c.top,bottom:c.bottom,left:c.left,right:c.right,animation:`spin ${c.dur} linear infinite`}} />
      ))}
      {/* ring */}
      <div style={{position:"absolute",width:340,height:340,borderRadius:"50%",border:`1.5px solid rgba(255,255,255,.12)`,animation:"spin 30s linear infinite"}} />
      <div style={{position:"absolute",width:240,height:240,borderRadius:"50%",border:`1px solid rgba(255,255,255,.08)`,animation:"spin 20s linear infinite reverse"}} />

      {/* logo - centered over background circles */}
      <div style={{
        display:"flex",flexDirection:"column",alignItems:"center",gap:12,
        position:"relative", zIndex:2,
      }}>
        {/* logo - centered in background circles */}
        <img
          src={LOGO_B64}
          alt="A7JZ"
          style={{
            width:220, height:220,
            objectFit:"contain",
            objectPosition:"center",
            filter:"drop-shadow(0 8px 24px rgba(0,0,0,.28))",
            opacity: phase>=1?1:0,
            transform: phase>=1?"translateY(0) scale(1)":"translateY(50px) scale(.9)",
            transition:"opacity .8s cubic-bezier(.22,1,.36,1), transform .8s cubic-bezier(.22,1,.36,1)",
            flexShrink:0,
          }}
        />

        {/* subtitle */}
        <div style={{
          fontSize:13,color:"rgba(255,255,255,.55)",letterSpacing:.5,marginTop:4,
          opacity:phase>=3?1:0,
          transition:"opacity .6s .2s ease",
        }}>منصة حجز الملاعب في بغداد</div>
      </div>

      {/* buttons */}
      <div style={{
        position:"absolute",bottom:52,width:"100%",maxWidth:400,padding:"0 28px",
        display:"flex",flexDirection:"column",gap:11,
        opacity:phase>=3?1:0,
        transform:phase>=3?"translateY(0)":"translateY(20px)",
        transition:"opacity .6s .35s ease, transform .6s .35s cubic-bezier(.22,1,.36,1)",
      }}>
        <button onClick={()=>onDone("reg")} style={{background:WH,color:P,border:"none",borderRadius:14,padding:14,fontSize:15,fontWeight:800,cursor:"pointer",boxShadow:"0 8px 24px rgba(0,0,0,.2)"}}>ابدأ الآن</button>
        <button onClick={()=>onDone("login")} style={{background:"rgba(255,255,255,.12)",color:WH,border:"1.5px solid rgba(255,255,255,.25)",borderRadius:14,padding:13,fontSize:15,fontWeight:600,cursor:"pointer",backdropFilter:"blur(8px)"}}>تسجيل الدخول</button>
        <button onClick={()=>onDone(null)} style={{background:"none",color:"rgba(255,255,255,.5)",border:"none",fontSize:13,cursor:"pointer",marginTop:2}}>تصفح بدون حساب</button>
      </div>
    </div>
  );
}

